// ========================================
// WF4 v3 - EXTRACT WEBHOOK DATA
// Fixed: Better payload parsing
// Updated: 28/12/2025
// ========================================

const payload = $input.first().json;
const row = payload.body?.data || payload.data || payload.body || payload;

let taskId = '', notes = '', status = '';

for (const [k, v] of Object.entries(row)) {
  const key = k.toLowerCase();
  if (key.includes('task') && key.includes('id')) taskId = v;
  else if (key.includes('ghi chú')) notes = v;
  else if (key.includes('trạng thái')) status = v;
}

let notionStatus = 'Đúng kế hoạch';
if (status.toLowerCase().includes('hoàn thành')) notionStatus = 'Hoàn thành';
else if (status.toLowerCase().includes('trễ')) notionStatus = 'Trễ tiến độ';
else if (status.toLowerCase().includes('chờ')) notionStatus = 'Chờ phản hồi';

const cleanTaskId = (taskId || '').toString().trim().replace(/-/g, '');

console.log('=== WF4 EXTRACT v3 ===');
console.log('Task ID:', cleanTaskId);
console.log('Notes:', notes);
console.log('Status:', notionStatus);

return {
  taskId: cleanTaskId,
  email: payload.respondentEmail || payload.body?.respondentEmail || 'hoangkha@esuhai.com',
  formResponseId: payload.formResponseId || payload.body?.formResponseId,
  timestamp: payload.timestamp || payload.body?.timestamp || new Date().toISOString(),
  notes: (notes || '').trim(),
  notionStatus,
  hasTaskId: cleanTaskId && cleanTaskId.length > 10,
  shouldProcess: cleanTaskId && cleanTaskId.length > 10
};

// ========================================
// WF4 v3 - BUILD UPDATE PAYLOAD
// Fixed: Property name "Tiêu đề" (not "Tên Task")
// Updated: 28/12/2025
// ========================================

const formData = $('📋 Extract Webhook Data').first().json;
const task = $input.first().json;

if (!task.properties) {
  throw new Error('Task not found or invalid');
}

// Get existing notes
const existing = task.properties['Ghi chú & Trở ngại']?.rich_text?.[0]?.plain_text || '';

// Build new note with timestamp
const ts = new Date(formData.timestamp).toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' });
const newNote = `[${ts}] ${formData.notes}`;
const finalNotes = existing ? existing + '\n\n' + newNote : newNote;

// Get task title - FIXED: Use "Tiêu đề" not "Tên Task"
let taskTitle = 'Task';
for (const [key, value] of Object.entries(task.properties)) {
  if (value.type === 'title' && value.title?.[0]) {
    taskTitle = value.title[0].plain_text;
    break;
  }
}

console.log('=== WF4 BUILD v3 ===');
console.log('Task Title:', taskTitle);
console.log('New Status:', formData.notionStatus);
console.log('Final Notes length:', finalNotes.length);

return {
  taskId: formData.taskId,
  email: formData.email,
  formResponseId: formData.formResponseId,
  taskTitle: taskTitle,
  taskUrl: task.url,
  notionStatus: formData.notionStatus,
  notes: formData.notes,
  updateBody: JSON.stringify({
    properties: {
      'Tình trạng': { select: { name: formData.notionStatus } },
      'Ghi chú & Trở ngại': { rich_text: [{ text: { content: finalNotes.substring(0, 2000) } }] }
    }
  })
};
